Content.Interface:
PROGRAM PG_RTPP
// ============================================================
// GENERIC SITE WRAPPER TEMPLATE
// Keep this file as the site adapter layer:
//   1) Map local site tags to FrontPOA/RearPOA/BOMTemp arrays
//   2) Set plant constants in VAR CONSTANT
//   3) Call the generic FB_RTPP block
// Generic library blocks (FB_RTPP, FB_RTPP_CALC, RTPP_REG,
// FB_SENSOR_AVG, UDT_SENSOR) should remain unchanged.
// ============================================================
VAR
	RTPP : FB_RTPP; // One instance of the generic FB per plant

	// Sensor arrays populated from site tags
	FrontPOA : ARRAY[1..30] OF UDT_SENSOR;
	RearPOA  : ARRAY[1..30] OF UDT_SENSOR;
	BOMTemp  : ARRAY[1..30] OF UDT_SENSOR;
END_VAR

VAR CONSTANT
	// Plant constants: change these per site
	PLANT_TOTAL_INVERTERS : REAL := 47.0;
	PLANT_DC_NOMINAL_MW   : REAL := 236.113;
	PLANT_COMM_YEAR       : DINT := 2024;
	PLANT_COMM_MONTH      : DINT := 8;
	PLANT_POI_LIMIT_MW    : REAL := 150.0;

	// Sensor counts: change these per site
	FRONT_SENSOR_COUNT    : INT := 4;
	REAR_SENSOR_COUNT     : INT := 4;
	BOM_SENSOR_COUNT      : INT := 12;

	// Electrical parameters: tune these per site
	BIFACIALITY           : REAL := 0.70;   // Module bifaciality coefficient
	TEMP_COEF             : REAL := -0.0034; // Power temp coefficient (%/degC, negative)
	DEGRADATION           : REAL := 0.005;  // Annual degradation fraction
	DC_LOSSES             : REAL := 0.005;  // DC losses fraction
	AC_LOSSES             : REAL := 0.015;  // AC losses fraction
	INV_EFFICIENCY        : REAL := 0.98;   // Inverter efficiency fraction
END_VAR

Content.Implementation:
// ============================================================
// IMPORT-SAFE TEMPLATE
// This implementation is intentionally commented to avoid import
// errors when site-specific tags are not present.
//
// Action required:
// 1) Uncomment this block.
// 2) Replace all placeholder/site example tags with your site tags.
// 3) Keep all site-specific mapping changes in this file only.
// ============================================================
(*
// ============================================================
// SECTION 1: Map site tags to front POA sensors
// ============================================================
FrontPOA[1].Quality := fPOA[1].q.validity;
FrontPOA[1].Value   := fPOA[1].instMag;
FrontPOA[2].Quality := fPOA[2].q.validity;
FrontPOA[2].Value   := fPOA[2].instMag;
FrontPOA[3].Quality := fPOA[3].q.validity;
FrontPOA[3].Value   := fPOA[3].instMag;
FrontPOA[4].Quality := fPOA[4].q.validity;
FrontPOA[4].Value   := fPOA[4].instMag;

// ============================================================
// SECTION 2: Map site tags to rear POA sensors
// ============================================================
RearPOA[1].Quality  := rPOA[1].q.validity;
RearPOA[1].Value    := rPOA[1].instMag;
RearPOA[2].Quality  := rPOA[2].q.validity;
RearPOA[2].Value    := rPOA[2].instMag;
RearPOA[3].Quality  := rPOA[3].q.validity;
RearPOA[3].Value    := rPOA[3].instMag;
RearPOA[4].Quality  := rPOA[4].q.validity;
RearPOA[4].Value    := rPOA[4].instMag;

// ============================================================
// SECTION 3: Map site tags to BOM temperature sensors
// ============================================================
BOMTemp[1].Quality  := BOM[1].q.validity;
BOMTemp[1].Value    := BOM[1].instMag;
BOMTemp[2].Quality  := BOM[2].q.validity;
BOMTemp[2].Value    := BOM[2].instMag;
BOMTemp[3].Quality  := BOM[3].q.validity;
BOMTemp[3].Value    := BOM[3].instMag;
BOMTemp[4].Quality  := BOM[4].q.validity;
BOMTemp[4].Value    := BOM[4].instMag;
BOMTemp[5].Quality  := BOM[5].q.validity;
BOMTemp[5].Value    := BOM[5].instMag;
BOMTemp[6].Quality  := BOM[6].q.validity;
BOMTemp[6].Value    := BOM[6].instMag;
BOMTemp[7].Quality  := BOM[7].q.validity;
BOMTemp[7].Value    := BOM[7].instMag;
BOMTemp[8].Quality  := BOM[8].q.validity;
BOMTemp[8].Value    := BOM[8].instMag;
BOMTemp[9].Quality  := BOM[9].q.validity;
BOMTemp[9].Value    := BOM[9].instMag;
BOMTemp[10].Quality := BOM[10].q.validity;
BOMTemp[10].Value   := BOM[10].instMag;
BOMTemp[11].Quality := BOM[11].q.validity;
BOMTemp[11].Value   := BOM[11].instMag;
BOMTemp[12].Quality := BOM[12].q.validity;
BOMTemp[12].Value   := BOM[12].instMag;

// ============================================================
// SECTION 4: Call generic RTPP function block
// Constants and tag mappings are the only site-specific parts.
// ============================================================
RTPP(
	// Inverter availability
	TotalInverters        := PLANT_TOTAL_INVERTERS,
	AvailableInverters    := inv_running.instMag,

	// Sensors
	FrontPOASensors       := FrontPOA,
	NumberOfFPOASensors   := FRONT_SENSOR_COUNT,
	RearPOASensors        := RearPOA,
	NumberOfRPOASensors   := REAR_SENSOR_COUNT,
	BOMTempSensors        := BOMTemp,
	NumberOfBOMTempSensors:= BOM_SENSOR_COUNT,

	// Plant parameters
	DCPowerNominalMW      := PLANT_DC_NOMINAL_MW,
	commYear              := PLANT_COMM_YEAR,
	commMonth             := PLANT_COMM_MONTH,

	// Electrical parameters
	BifacialityFactor     := BIFACIALITY,
	TempCoef              := TEMP_COEF,
	DegradationRate       := DEGRADATION,
	DCLossesPercent       := DC_LOSSES,
	ACLossesPercent       := AC_LOSSES,
	InvEfficiency         := INV_EFFICIENCY,
	PlantPOILimitMW       := PLANT_POI_LIMIT_MW,

	// Regression conditioning (site tags)
	// ActivePowerMW must be PV-only generation in MW.
	// BESS site: if a BESS is present, do NOT use the POI meter here — use a
	// dedicated PV generation meter, or subtract BESS active power from the POI
	// meter. Passing POI power when the BESS is charging or discharging will
	// corrupt the regression coefficients.
	ActivePowerMW         := pv_gen.instMag * 0.001,
	PSetpointMW           := setpoint.instMag
);

// ============================================================
// SECTION 5: Write generic outputs
// ============================================================
RTPP_OUTPUT.instMag := RTPP.RTPP_MW;
RTPP_OUTPUT.t       := System_Time_Control_POU.System_Time;
RTPP_OUTPUT.q       := GOOD_QUALITY;

HSL_OUTPUT.instMag  := RTPP.HSL_MW;
HSL_OUTPUT.t        := System_Time_Control_POU.System_Time;
HSL_OUTPUT.q        := GOOD_QUALITY;

// --- Diagnostics to globals (optional, useful for SCADA trending) ---
FRONT_POA_AVG          := RTPP.FrontPOA_Avg;
REAR_POA_AVG           := RTPP.RearPOA_Avg;
BOM_AVG                := RTPP.BOMTemp_Avg;
*)
